def trace(url):
    urls = [url]

    while True:
        parsed = urlparse(url)
        if parsed.scheme not in {'http', 'https'}:
            raise ValueError('Invalid scheme')

        if 'example.com' in parsed.netloc:
            resp = requests.head(url)

            if resp.is_redirect:
                url = resp.headers['Location']

                if url in urls:
                    break

                urls.append(url)
            else:
                break
        else:
            raise ValueError('Forbidden domain')

